class bp extends hr {
  static toRating(e) {
    return {
      source: e.email,
      rating: e.rating > 0 ? (e.rating - 1) / 254 * st.maxRatingScore : void 0
    };
  }
  constructor() {
    super(["ID3v2.3", "ID3v2.4"], jg);
  }
  /**
   * Handle post mapping exceptions / correction
   * @param tag to post map
   * @param warnings Wil be used to register (collect) warnings
   */
  postMap(e, a) {
    switch (e.id) {
      case "UFID":
        {
          const i = e.value;
          i.owner_identifier === "http://musicbrainz.org" && (e.id += `:${i.owner_identifier}`, e.value = As(i.identifier, "latin1"));
        }
        break;
      case "PRIV":
        {
          const i = e.value;
          switch (i.owner_identifier) {
            case "AverageLevel":
            case "PeakValue":
              e.id += `:${i.owner_identifier}`, e.value = i.data.length === 4 ? pe.get(i.data, 0) : null, e.value === null && a.addWarning("Failed to parse PRIV:PeakValue");
              break;
            default:
              a.addWarning(`Unknown PRIV owner-identifier: ${i.data}`);
          }
        }
        break;
      case "POPM":
        e.value = bp.toRating(e.value);
        break;
    }
  }
}
